Sub 'WriteColumnTitles'

	&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Razão Social"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Nome Fantasia"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "CEP"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "UF"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Cidade"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Bairro"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Endereço"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Ult.Compra"
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Dat.Cadast."
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11
	&ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "1° Fone"
	if &CnpjIE = 'S'
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Bold = True
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Color = 11
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = "CPF/CNPJ"

		&ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Bold = True
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Color = 11
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Text = "RG/I.E."
	EndIF

EndSub

Sub 'WriteData'

	For Each 
		Order EmpCod, PesRaz when &Ordenar = 'A'
		Order EmpCod, PesCod when &Ordenar = 'N'
		Order EmpCod, PesEntUfeCod, PesEntCidNom, PesEntBai, PesEntLog  when &Ordenar = 'E'

		Where EmpCod = &EmpCod
		Where PesIntVenCod = &PesIntVenCod or PesExtVenCod = &PesIntVenCod when not &PesIntVenCod.IsEmpty()
		Where PesSts = &PesSts when not &PesSts.IsEmpty()
		Where PesUltVenDta >= &PesUltVenDta when not &PesUltVenDta.IsEmpty()
		Where PesUltVenDta <= &PesUltVenDtaDia when not &PesUltVenDtaDia.IsEmpty()
		where PesDtaCad >= &PesDtaCad when not &PesDtaCad.IsEmpty()
		Where PesEntCidCod = &PesEntCidCod When not &PesEntCidCod.IsEmpty()
		Where PesEntUfeCod = &PesEntUfeCod when not &PesEntUfeCod.IsEmpty()
		Where PesCidAreCod = &PesCidAreCod when not &PesCidAreCod.IsEmpty()
		Where RatCod = &RatCod when not &RatCod.IsEmpty()
		Where PesIsCli = True
		where PesReg = &PesReg when &PesReg <> 'T'
		Where PesDtaUltCom >= &PesDtaUltCom when not &PesDtaUltCom.IsEmpty()
		&CellRow += 1

		Do 'BeforeWriteLine'
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PesCod
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = PesRaz
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = PesSts.EnumerationDescription()
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = trim(PesEntCep)
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = PesCidUfeCod
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = PesCidNom

		&ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = PesEntBai.Trim()
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = PesEntLogNro
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = PesUltVenDta.ToString()
		&ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = PesDtaCad.ToString()

		&ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = PesPrmFon.ToString()

		if &CnpjIE = 'S'
			if PesTip = TipoPessoa.JURIDICA
				&ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = PesCnpj
				&ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Text = PesInsEst
			Else
				&ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = PesCpf
				&ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Text = PesRg
			EndIF
		EndIF

		Do 'AfterWriteLine'

	Endfor

EndSub

Sub 'CloseDocument'

	&ExcelDocument.Save()
	Do 'CheckStatus'
	&ExcelDocument.Close()

EndSub

Sub 'CheckStatus'

	If (&ExcelDocument.ErrCode <> 0)
		&Filename = ""
		&ErrorMessage = &ExcelDocument.ErrDescription
		&ExcelDocument.Close()
		Return
	EndIf

